DROP TABLE IF EXISTS `products_config`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `products_config` (
  `product_config_id` int NOT NULL AUTO_INCREMENT,
  `parent_product_id` int NOT NULL,
  `child_product_id` int NOT NULL,
  PRIMARY KEY (`product_config_id`),
  KEY `parent_product_id` (`parent_product_id`),
  KEY `child_product_id` (`child_product_id`),
  CONSTRAINT `products_config_ibfk_1` FOREIGN KEY (`parent_product_id`) REFERENCES `products` (`product_id`),
